    "startFrame": 13159,
    "durationSec": 3.8186666666666667,
    "durationFrames": 115,
    "speaker": "ずんだもん",
    "text": "そうなのだ。でもここで一番大きな疑問が残るのだ。",
    "speakerColor": "#22c55e",
