    "startFrame": 14138,
    "durationSec": 4.725333333333333,
    "durationFrames": 142,
    "speaker": "ずんだもん",
    "text": "アインシュタインはミュンヘンのルイトポルト・ギムナジウムに通っていたのだ。",
    "speakerColor": "#22c55e",
